import * as React from "react"
import { cn } from "@/lib/utils"
import {
  ChevronRight,
  ChevronDown,
  MousePointer,
  Pencil,
  Minus,
  Square,
  Circle,
  PenTool,
  Star,
  Hexagon,
  FileText,
  Layers,
} from "lucide-react"

export interface TreeNode {
  id: string
  key: string
  title: string
  tagName: string
  name?: string
  dataType?: string
  disabled?: boolean
  children?: TreeNode[]
  icon?: React.ReactNode
}

export interface TreeProps {
  data: TreeNode[]
  selectedKeys?: string[]
  expandedKeys?: string[]
  onSelect?: (keys: string[]) => void
  onExpand?: (keys: string[]) => void
  className?: string
}

const iconMap: Record<string, React.ReactNode> = {
  select: <MousePointer size={14} />,
  fhpath: <Pencil size={14} />,
  line: <Minus size={14} />,
  rect: <Square size={14} />,
  ellipse: <Circle size={14} />,
  path: <PenTool size={14} />,
  star: <Star size={14} />,
  polygon: <Hexagon size={14} />,
  g: <Layers size={14} />,
  default: <FileText size={14} />,
}

const TreeNodeComponent: React.FC<{
  node: TreeNode
  level: number
  selectedKeys?: string[]
  expandedKeys?: string[]
  onSelect?: (key: string) => void
  onExpand?: (key: string) => void
}> = ({ node, level, selectedKeys, expandedKeys, onSelect, onExpand }) => {
  const isSelected = selectedKeys?.includes(node.id)
  const isExpanded = expandedKeys?.includes(node.id)
  const hasChildren = node.children && node.children.length > 0

  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation()
    if (!node.disabled) {
      onSelect?.(node.id)
    }
  }

  const handleExpand = (e: React.MouseEvent) => {
    e.stopPropagation()
    if (hasChildren) {
      onExpand?.(node.id)
    }
  }

  const getIcon = () => {
    if (node.icon) return node.icon
    if (iconMap[node.dataType || ""]) return iconMap[node.dataType || ""]
    if (iconMap[node.tagName || ""]) return iconMap[node.tagName || ""]
    return iconMap.default
  }

  return (
    <div className={cn("tree-node", isSelected && "tree-node-selected")}>
      <div
        className={cn(
          "tree-node-content",
          node.disabled && "tree-node-disabled"
        )}
        style={{ paddingLeft: `${level * 16 + 8}px` }}
        onClick={handleClick}
      >
        {hasChildren && (
          <button
            className="tree-node-expand"
            onClick={handleExpand}
          >
            {isExpanded ? (
              <ChevronDown size={12} />
            ) : (
              <ChevronRight size={12} />
            )}
          </button>
        )}
        {!hasChildren && <span className="tree-node-spacer" />}
        <span className="tree-node-icon">{getIcon()}</span>
        <span className="tree-node-label">{node.title}</span>
      </div>

      {hasChildren && isExpanded && (
        <div className="tree-node-children">
          {node.children?.map((child) => (
            <TreeNodeComponent
              key={child.id}
              node={child}
              level={level + 1}
              selectedKeys={selectedKeys}
              expandedKeys={expandedKeys}
              onSelect={onSelect}
              onExpand={onExpand}
            />
          ))}
        </div>
      )}
    </div>
  )
}

export const Tree = React.forwardRef<HTMLDivElement, TreeProps>(
  (
    { data = [], selectedKeys = [], expandedKeys = [], onSelect, onExpand, className },
    ref
  ) => {
    const handleNodeSelect = (key: string) => {
      onSelect?.([key])
    }

    const handleNodeExpand = (key: string) => {
      if (expandedKeys.includes(key)) {
        onExpand?.(expandedKeys.filter((k) => k !== key))
      } else {
        onExpand?.([...expandedKeys, key])
      }
    }

    return (
      <div
        ref={ref}
        className={cn("tree", className)}
      >
        {data.map((node) => (
          <TreeNodeComponent
            key={node.id}
            node={node}
            level={0}
            selectedKeys={selectedKeys}
            expandedKeys={expandedKeys}
            onSelect={handleNodeSelect}
            onExpand={handleNodeExpand}
          />
        ))}
      </div>
    )
  }
)

Tree.displayName = "Tree"

import * as React from "react"
import { cn } from "@/lib/utils"

export interface Property {
  key: string
  label: string
  type: "text" | "number" | "color" | "select" | "slider"
  value: any
  options?: { label: string; value: any }[]
  min?: number
  max?: number
  step?: number
  unit?: string
  onChange?: (value: any) => void
}

export interface PropertyPanelProps {
  title?: string
  properties: Property[]
  onChange?: (key: string, value: any) => void
  className?: string
}

const PropertyItem: React.FC<{
  property: Property
  onChange?: (key: string, value: any) => void
}> = ({ property, onChange }) => {
  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(property.key, property.type === 'number' ? parseFloat(e.target.value) : e.target.value)
  }

  const handleSelectChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    onChange?.(property.key, e.target.value)
  }

  const handleSliderChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    onChange?.(property.key, parseFloat(e.target.value))
  }

  switch (property.type) {
    case "text":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <input
            type="text"
            value={property.value || ""}
            onChange={handleInputChange}
            className="property-input"
          />
        </div>
      )

    case "number":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <input
            type="number"
            value={property.value ?? 0}
            onChange={handleInputChange}
            className="property-input"
          />
        </div>
      )

    case "color":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <div className="flex items-center gap-2">
            <input
              type="color"
              value={property.value || "#000000"}
              onChange={handleInputChange}
              className="w-10 h-10 rounded cursor-pointer"
            />
            <input
              type="text"
              value={property.value || ""}
              onChange={handleInputChange}
              className="property-input flex-1"
            />
          </div>
        </div>
      )

    case "select":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <select
            value={property.value ?? ""}
            onChange={handleSelectChange}
            className="property-select"
          >
            {property.options?.map((option) => (
              <option key={option.value} value={option.value}>
                {option.label}
              </option>
            ))}
          </select>
        </div>
      )

    case "slider":
      return (
        <div className="property-item">
          <label className="property-label">{property.label}</label>
          <div className="flex items-center gap-2 flex-1">
            <input
              type="range"
              value={property.value ?? 0}
              onChange={handleSliderChange}
              min={property.min}
              max={property.max}
              step={property.step}
              className="flex-1"
              style={{ flex: 1 }}
            />
            <input
              type="number"
              value={property.value ?? 0}
              onChange={handleInputChange}
              min={property.min}
              max={property.max}
              step={property.step}
              className="property-input"
              style={{ minWidth: "60px", width: "60px" }}
            />
            {property.unit && <span className="text-xs text-slate-500">{property.unit}</span>}
          </div>
        </div>
      )

    default:
      return null
  }
}

export const PropertyPanel = React.forwardRef<HTMLDivElement, PropertyPanelProps>(
  (
    {
      title = "属性",
      properties = [],
      onChange,
      className,
    },
    ref
  ) => {
    // 添加调试日志
    React.useEffect(() => {
      console.log('[PropertyPanel] properties 更新:', properties.length, '个属性')
      console.log('[PropertyPanel] properties 详情:', properties.map(p => ({ key: p.key, label: p.label, value: p.value })))
    }, [properties])

    const handlePropertyChange = (key: string, value: any) => {
      console.log('[PropertyPanel] 属性变化:', key, '=', value)
      onChange?.(key, value)
    }

    // 分组属性
    const groupedProperties = React.useMemo(() => {
      const groups: Record<string, Property[]> = {}

      properties.forEach((prop) => {
        const group = prop.key.split(".")[0]
        if (!groups[group]) {
          groups[group] = []
        }
        groups[group].push(prop)
      })

      console.log('[PropertyPanel] 分组后的属性:', Object.keys(groups), '->', Object.values(groups).map(g => g.length))

      return groups
    }, [properties])

    return (
      <div ref={ref} className={cn("property-panel", className)}>
        <div className="property-panel-header">
          <h3 className="text-sm font-semibold">{title}</h3>
        </div>

        <div className="property-panel-content">
          {Object.entries(groupedProperties).map(([groupName, groupProps]) => (
            <div key={groupName} className="property-group">
              <h4 className="property-group-title">{groupName}</h4>
              {groupProps.map((prop) => (
                <PropertyItem
                  key={prop.key}
                  property={prop}
                  onChange={handlePropertyChange}
                />
              ))}
            </div>
          ))}

          {properties.length === 0 && (
            <div className="property-empty">
              <p className="text-sm text-slate-500">未选择任何元素</p>
            </div>
          )}
        </div>
      </div>
    )
  }
)

