  /**
   * 默认展开的面板索引（从 0 开始）
   * 手风琴模式：单个数字，多开模式：数字数组
   * @default 0
   */
  defaultValue?: number | number[]
  /**
   * 受控模式：当前展开的面板索引
   */
  value?: string | string[]
  /**
   * 展开状态变化回调
   */
  onValueChange?: (value: string | string[]) => void
  /**
   * 子元素（如果提供 panels，则忽略 children）
   */
  children?: React.ReactNode
}

const Panel = React.forwardRef<HTMLDivElement, PanelProps>(
  (
    {
      className,
      accordion = true,
      collapsible = false,
      panels,
      defaultValue = 0,
      value,
      onValueChange,
      children,
      ...props
    },
    ref
  ) => {
    // 计算默认值
    const getDefaultValue = () => {
      if (accordion) {
        // 手风琴模式：单个值
        if (typeof defaultValue === "number") {
          return `panel-${defaultValue}`
        }
        return `panel-0`
      } else {
        // 多开模式：数组
        if (Array.isArray(defaultValue)) {
          return defaultValue.map((i) => `panel-${i}`)
        }
        return [`panel-0`]
      }
    }

    // 渲染配置模式的面板
    const renderConfigPanels = () => {
      if (!panels || panels.length === 0) {
        return null
      }

      const childrenArray = React.Children.toArray(children)

      return panels.map((panel, index) => {
        const panelValue = `panel-${index}`
        return (
          <AccordionItem key={panelValue} value={panelValue}>
            <AccordionTrigger>{panel.title || `面板 ${index + 1}`}</AccordionTrigger>
            <AccordionContent
              forceMount={panel.forceRender}
            >
              {childrenArray[index] || (
                <div className="flex items-center justify-center h-full text-slate-400">
                  <p>面板内容区域 {index + 1}</p>
                </div>
              )}
            </AccordionContent>
          </AccordionItem>
        )
      })
    }

    // 渲染 children 模式的面板
    const renderChildrenPanels = () => {
      return children
    }

    return (
      <div
        ref={ref}
        className={cn("panel-container", className)}
        {...props}
      >
        <Accordion
          type={accordion ? "single" : "multiple"}
          {...(collapsible && { collapsible: true })}
          defaultValue={getDefaultValue()}
          value={value}
          onValueChange={onValueChange}
          className="w-full"
        >
          {panels && panels.length > 0 ? renderConfigPanels() : renderChildrenPanels()}
        </Accordion>
      </div>
    )
  }
)

Panel.displayName = "Panel"

export { Panel }

import * as React from "react"
import { cn } from "@/lib/utils"
import {
  Popover as ShadcnPopover,
  PopoverTrigger,
  PopoverContent,
} from "@/components/ui/popover"
import { Button } from "@/registry/blocks/components/button/button"

export interface PopoverProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * 按钮文字
   */
  buttonName?: string
  /**
   * 隐藏按钮
   */
  hiddenBtn?: boolean
  /**
   * 禁用状态
   */
  disable?: boolean
  /**
   * 触发方式
   */
  trigger?: 'hover' | 'click'
  /**
   * 位置
   */
  placement?: 'top' | 'bottom' | 'left' | 'right'
  /**
   * 宽度
   */
  width?: number | string
  /**
   * 高度
   */
  height?: number | string
  /**
   * 是否打开
   */
  open?: boolean
  /**
   * 打开状态变化回调
   */
  onOpenChange?: (open: boolean) => void
  /**
   * 子元素
   */
  children?: React.ReactNode
}

const Popover = React.forwardRef<HTMLDivElement, PopoverProps>(
  (
    {
      className,
      buttonName = '气泡卡片',
      hiddenBtn = false,
      disable = false,
      trigger = 'click',
      placement = 'top',
      width = 200,
      height = 200,
      open,
      onOpenChange,
      children,
      ...props
    },
    ref
  ) => {
    // 内部状态管理（当 open 未受控时使用）
    const [internalOpen, setInternalOpen] = React.useState(false)

    // 判断是否受控
    const isControlled = open !== undefined
    const isOpen = isControlled ? open : internalOpen

    // 处理打开/关闭
    const handleOpenChange = (newOpen: boolean) => {
      if (!isControlled) {
        setInternalOpen(newOpen)
      }
      onOpenChange?.(newOpen)
    }

    // 计算内容样式
    const contentStyle = React.useMemo(() => {
      const style: React.CSSProperties = {}
      if (typeof width === 'number') {
        style.width = `${width}px`
      } else if (typeof width === 'string') {
        style.width = width
      }

      if (typeof height === 'number') {
        style.height = `${height}px`
      } else if (typeof height === 'string') {
        style.height = height
      }

      return style
    }, [width, height])

    // 渲染触发按钮
    const renderTrigger = () => {
      if (hiddenBtn) {
        return <div style={{ width: '100%', height: '100%' }} />
      }

      // hover 模式：使用 PopoverTrigger + 自定义鼠标事件处理
      if (trigger === 'hover') {
        return (
          <PopoverTrigger asChild>
            <div
              onMouseEnter={() => handleOpenChange(true)}
              onMouseLeave={() => handleOpenChange(false)}
              style={{ width: '100%', height: '100%' }}
            >
              <Button
                variant="outline"
                disabled={disable}
                style={{ width: '100%', height: '100%' }}
                onPointerDown={(e) => e.preventDefault()}
              >
                {buttonName}
              </Button>
            </div>
          </PopoverTrigger>
        )
      }

      // click 模式：使用 PopoverTrigger
      return (
        <PopoverTrigger asChild>
          <Button
            variant="outline"
            disabled={disable}
            style={{ width: '100%', height: '100%' }}
          >
            {buttonName}
          </Button>
        </PopoverTrigger>
      )
    }

    return (
      <div
        ref={ref}
        className={cn("popover-container", className)}
        style={{ height: '100%' }}
        {...props}
      >
        <ShadcnPopover
          open={isOpen}
          onOpenChange={handleOpenChange}
        >
          {renderTrigger()}

          <PopoverContent
            align={placement === 'left' || placement === 'right' ? 'center' : undefined}
            side={
              placement === 'top' ? 'top' :
              placement === 'bottom' ? 'bottom' :
              placement === 'left' ? 'left' :
              placement === 'right' ? 'right' : undefined
            }
            style={contentStyle}
            onOpenAutoFocus={(e: React.SyntheticEvent) => {
              // hover 模式下不自动聚焦
              if (trigger === 'hover') {
                e.preventDefault()
              }
            }}
          >
            <div
              className="popover-content"
              style={{
                width: '100%',
                height: '100%',
                overflow: 'auto'
              }}
            >
              {children}
            </div>
          </PopoverContent>
        </ShadcnPopover>
      </div>
    )
  }
)

Popover.displayName = "Popover"

export { Popover }

import * as React from "react"
import { cn } from "@/lib/utils"
import {
  Tabs as ShadcnTabs,
  TabsList,
  TabsTrigger,
  TabsContent,
} from "@/components/ui/tabs"

export interface TabConfig {
  /**
   * 标签标题
   */
  title: string
  /**
   * 标签图标 URL
   */
  icon?: string
  /**
   * 选中状态的图标 URL
   */
  selectedIcon?: string
  /**
   * 强制渲染（即使未展开也渲染 DOM）
   */
  forceRender?: boolean
}

export interface TabsProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * 标签配置数组
   */
  tabs: TabConfig[]
  /**
   * 默认激活的标签索引（从 0 开始）
   * @default 0
   */
  defaultValue?: string
  /**
   * 受控模式：当前激活的标签值
   */
  value?: string
  /**
   * 激活状态变化回调
   */
  onValueChange?: (value: string) => void
  /**
   * 标签位置
   * @default 'top'
   */
  orientation?: 'top' | 'bottom' | 'left' | 'right'
  /**
   * 标签样式
   * @default 'line'
   */
  variant?: 'line' | 'card'
  /**
   * 隐藏时销毁未激活的标签内容
   * @default false
   */
  destroyInactiveTabPane?: boolean
  /**
   * 子元素
   */
  children?: React.ReactNode
}

const Tabs = React.forwardRef<HTMLDivElement, TabsProps>(
  (
    {
      className,
      tabs = [],
      defaultValue = "tab-0",
      value,
      onValueChange,
      orientation = "top",
      variant = "line",
      destroyInactiveTabPane = false,
      children,
      ...props
    },
    ref
  ) => {
    const childrenArray = React.Children.toArray(children)

    // 渲染标签触发器
    const renderTriggers = () => {
      return tabs.map((tab, index) => {
        const tabValue = `tab-${index}`
        const iconUrl = value === tabValue && tab.selectedIcon ? tab.selectedIcon : tab.icon

        return (
          <TabsTrigger
            key={tabValue}
            value={tabValue}
            className={cn(
              "gap-2",
              variant === "card" && "data-[state=active]:bg-background data-[state=active]:border-b-2 data-[state=active]:border-primary"
            )}
          >
            {iconUrl && (
              <img
                src={iconUrl}
                alt=""
                style={{ width: 14, height: 14 }}
              />
            )}
            {tab.title || `Tab ${index + 1}`}
          </TabsTrigger>
        )
      })
    }

    // 渲染标签内容
    const renderContents = () => {
      return tabs.map((tab, index) => {
        const tabValue = `tab-${index}`

        return (
          <TabsContent
            key={tabValue}
            value={tabValue}
            forceMount={tab.forceRender}
            className={cn(
              "mt-0 flex-1",
              orientation === "left" || orientation === "right" ? "ml-0" : ""
            )}
          >
            {childrenArray[index] || (
              <div className="flex items-center justify-center h-full text-slate-400">
                <p>标签内容区域 {index + 1}</p>
              </div>
            )}
          </TabsContent>
        )
      })
    }

    // 获取 Radix UI 的 orientation
    const getRadixOrientation = (): "horizontal" | "vertical" => {
      return orientation === "left" || orientation === "right" ? "vertical" : "horizontal"
    }

    // 获取容器布局类
    const getContainerClass = () => {
      switch (orientation) {
        case "left":
          return "flex flex-row"
        case "right":
          return "flex flex-row-reverse"
        case "bottom":
          return "flex flex-col-reverse"
        default:
          return "flex flex-col"
      }
    }

    // 获取 TabsList 样式
    const getTabsListClass = () => {
      const baseClasses = "justify-start"

      if (orientation === "left" || orientation === "right") {
        return cn(
          baseClasses,
          "flex-col items-stretch h-full w-auto min-w-[120px] border-r"
        )
      }

      if (orientation === "bottom") {
        return cn(
          baseClasses,
          "flex-row w-full border-t"
        )
      }

      // top
      return cn(
        baseClasses,
        "flex-row w-full border-b"
      )
    }

    return (
      <div
        ref={ref}
        className={cn("tabs-container w-full h-full", className)}
        {...props}
      >
        <ShadcnTabs
          defaultValue={defaultValue}
          value={value}
          onValueChange={onValueChange}
          orientation={getRadixOrientation()}
          className={cn(getContainerClass())}
        >
          <TabsList
            className={cn(
              getTabsListClass(),
              variant === "card" && "bg-muted/50 p-1 m-0 border-0"
            )}
          >
            {renderTriggers()}
          </TabsList>
          {renderContents()}
        </ShadcnTabs>
      </div>
    )
  }
)

Tabs.displayName = "Tabs"

export { Tabs }

