export default DateRange

import { Button } from "@/components/ui/button"
import {
  Field,
  FieldDescription,
  FieldError,
  FieldLabel,
} from "@/components/ui/field"
import { Input } from '@/components/ui/input'
import { Controller, useFieldUIStateValue, useFormContext } from '@airiot/client'
import type { ReactNode } from 'react'
import React, { cloneElement } from 'react'
import fieldMap from './field-map'
import { cn } from '@/lib/utils'

type FormFieldProps = {
  name: string
  label?: ReactNode
  type?: string
  description?: ReactNode
  children?: ReactNode | ((props: any) => ReactNode)
  required?: boolean
  rules?: any
  className?: string
  classNames?: Record<'field' | 'label' | 'input' | 'description' | 'error', string>
  [key: string]: any
}

type FormContextReturnType = ReturnType<typeof useFormContext> & {
  classNames?: Record<'form' | 'field' | 'label' | 'input' | 'description' | 'error', string>
}

const FormField = 
  ({ name, label, type, description, children, required, rules, className, classNames, ...restProps }: FormFieldProps) => {
  let methods = null
  try {
    methods = useFormContext() as FormContextReturnType
  } catch {
    return <Button variant={"destructive"}>FormField must be used within a Form.</Button>
  }

  const ui = useFieldUIStateValue(name)
  const ContorlComponent = type && fieldMap[type] || Input
  const fieldId = `form-rhf-${name}` + (Math.random().toString(36).substring(2, 9))
  const formClassNames = methods?.classNames

  return ui.visible ? (
    <Controller
        name={name}
        control={methods?.control}
        rules={{ required, ...rules }}
        render={({ field, fieldState }) => (
        <Field data-invalid={fieldState.invalid} 
          className={cn(className, formClassNames?.field, classNames?.field)}>
          { label && <FieldLabel htmlFor={fieldId} className={cn(formClassNames?.label, classNames?.label)}>
            {label}{required && <span className="text-red-500">*</span>}
          </FieldLabel>}
          {
            children ? ( typeof children === 'function' ? children({
              id: fieldId,
              ...field,
              ...restProps,
              className: cn(formClassNames?.input, classNames?.input),
              'aria-invalid': fieldState.invalid
            }) : cloneElement(children as React.ReactElement<any>, {
              id: fieldId,
              ...field,
              ...restProps,
              className: cn(formClassNames?.input, classNames?.input),
              'aria-invalid': fieldState.invalid
            }) ) : (
              <ContorlComponent
                id={fieldId}
                {...field}
                {...restProps}
                className={cn(formClassNames?.input, classNames?.input)}
                aria-invalid={fieldState.invalid}
              />
            )
          }
          {description && (
            <FieldDescription className={cn(formClassNames?.description, classNames?.description)}>
              {description}
            </FieldDescription>
          )}
          {fieldState.invalid && (
            <FieldError errors={[fieldState.error]} className={cn(formClassNames?.error, classNames?.error)} />
          )}
        </Field>
      )}
    />
  ) : null
}

export default FormField

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import {
  InputGroup,
  InputGroupAddon,
  InputGroupInput,
} from "@/components/ui/input-group"

const inputNumberVariants = cva(
  "relative border transition-colors",
  {
    variants: {
      variant: {
        default: "border-border bg-background",
        outline: "border-2 border-primary",
        filled: "border-primary/20 bg-primary/5",
        ghost: "border-transparent hover:bg-accent/50",
      },
      size: {
        sm: "h-8 text-sm",
        md: "h-10 text-base",
        lg: "h-12 text-lg",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "md",
    },
  }
)

export interface InputNumberProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange" | "onBlur" | "onFocus" | "onInput" | "prefix">,
  VariantProps<typeof inputNumberVariants> {
  /**
   * 当前值
   */
  value?: number
  /**
   * 默认值
   */
  defaultValue?: number
  /**
   * 占位提示
   */
  placeholder?: string
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 是否只读
   */
  readOnly?: boolean
  /**
   * 是否显示边框
   */
  bordered?: boolean
  /**
   * 最大值
   */
  max?: number
  /**
   * 最小值
   */
  min?: number
  /**
   * 数值精度
   */
  precision?: number
  /**
   * 步长
   */
  step?: number
  /**
   * 前缀
   */
  prefix?: React.ReactNode
  /**
   * 后缀
   */
  suffix?: React.ReactNode
  /**
   * 前置标签
   */
  addonBefore?: React.ReactNode
  /**
   * 后置标签
   */
  addonAfter?: React.ReactNode
  /**
   * 自动聚焦
   */
  autoFocus?: boolean
  /**
   * 值变化回调
   */
  onChange?: (value: number | undefined, event: React.ChangeEvent<HTMLInputElement>) => void
  /**
   * 回车回调
   */
  onPressEnter?: (event: React.KeyboardEvent<HTMLInputElement>) => void
  /**
   * 失焦回调
   */
  onBlur?: (event: React.FocusEvent<HTMLInputElement>) => void
  /**
   * 聚焦回调
   */
  onFocus?: (event: React.FocusEvent<HTMLInputElement>) => void
  /**
   * 输入回调
   */
  onInput?: (event: React.ChangeEvent<HTMLInputElement>) => void
}

const FormInputNumber = React.forwardRef<HTMLDivElement, InputNumberProps>(
  (
    {
      className,
      value: controlledValue,
      defaultValue,
      placeholder = "请输入数字",
      disabled = false,
      readOnly = false,
      bordered = true,
      max,
      min,
      precision,
      step = 1,
      prefix,
      suffix,
      addonBefore,
      addonAfter,
      autoFocus = false,
      onChange,
      onPressEnter,
      onBlur,
      onFocus,
      onInput,
      variant,
      size,
      style,
      ...props
    },
    ref
  ) => {
    const [internalValue, setInternalValue] = React.useState(defaultValue?.toString() || "")
    const [displayValue, setDisplayValue] = React.useState("")
    const inputRef = React.useRef<HTMLInputElement>(null)

    const isControlled = controlledValue !== undefined
    const numericValue = isControlled ? controlledValue : (internalValue ? parseFloat(internalValue) : undefined)

    // 格式化显示值
    const formatValue = React.useCallback((val: number | undefined): string => {
      if (val === undefined || val === null || isNaN(val)) return ""
      if (precision !== undefined) {
        return val.toFixed(precision)
      }
      return val.toString()
    }, [precision])

    // 更新显示值
    React.useEffect(() => {
      setDisplayValue(formatValue(numericValue))
    }, [numericValue, formatValue])

    // 验证和限制数值
    const validateAndClampValue = React.useCallback((val: number): number => {
      let clampedValue = val

      if (min !== undefined && clampedValue < min) {
        clampedValue = min
      }
      if (max !== undefined && clampedValue > max) {
        clampedValue = max
      }

      if (precision !== undefined) {
        clampedValue = parseFloat(clampedValue.toFixed(precision))
      }

      return clampedValue
    }, [min, max, precision])

    // 处理输入变化
    const handleInputChange = React.useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const inputValue = e.target.value

        // 允许空值、数字、负号、小数点
        if (inputValue === "" || /^-?\d*\.?\d*$/.test(inputValue)) {
          setDisplayValue(inputValue)

          // 如果是有效数字，更新内部值
          const numericVal = inputValue === "" ? undefined : parseFloat(inputValue)
          if (numericVal !== undefined && !isNaN(numericVal)) {

            if (!isControlled) {
              setInternalValue(numericVal.toString())
            }

            onChange?.(numericVal, e)
          } else if (inputValue === "") {
            if (!isControlled) {
              setInternalValue("")
            }
            onChange?.(undefined, e)
          }
        }

        onInput?.(e)
      },
      [isControlled, controlledValue, validateAndClampValue, onChange, onInput]
    )

    // 处理失焦时的最小/最大/精度处理并格式化显示
    const handleBlur = React.useCallback(
      (e: React.FocusEvent<HTMLInputElement>) => {
        const val = displayValue?.trim()

        if (val === "") {
          if (!isControlled) {
            setInternalValue("")
          }
          const mockEvent = { target: { value: "" } } as React.ChangeEvent<HTMLInputElement>
          onChange?.(undefined, mockEvent)
        } else {
          const numeric = parseFloat(val as string)
          if (!isNaN(numeric)) {
            const clamped = validateAndClampValue(numeric)
            if (!isControlled) {
              setInternalValue(clamped.toString())
            }
            setDisplayValue(formatValue(clamped))
            const mockEvent = {
              target: { value: clamped.toString() },
            } as React.ChangeEvent<HTMLInputElement>
            onChange?.(clamped, mockEvent)
          } else {
            // 非数字输入，恢复为格式化的当前数值
            setDisplayValue(formatValue(numericValue))
          }
        }

        onBlur?.(e)
      },
      [displayValue, isControlled, validateAndClampValue, formatValue, onChange, onBlur, numericValue]
    )

    // 自动聚焦
    React.useEffect(() => {
      if (autoFocus && inputRef.current) {
        inputRef.current.focus()
      }
    }, [autoFocus])

    const inputElement = (
      <InputGroupInput
        ref={inputRef}
        type="number"
        value={displayValue}
        onChange={handleInputChange}
        onBlur={handleBlur}
        onFocus={onFocus}
        placeholder={placeholder}
        disabled={disabled}
        readOnly={readOnly}
        min={min}
        max={max}
        step={step}
        className={cn(
          !bordered && "border-0",
          "focus-visible:ring-ring focus-visible:ring-offset-0"
        )}
        {...props}
      />
    )

    if (addonBefore || addonAfter) {
      return (
        <InputGroup
          ref={ref}
          className={cn(
            inputNumberVariants({ variant, size }),
            !bordered && "border-transparent",
            disabled && "opacity-50 cursor-not-allowed",
            readOnly && "cursor-default",
            className
          )}
          style={style}
        >
          {addonBefore && <InputGroupAddon align="inline-start">{addonBefore}</InputGroupAddon>}
          <div className="relative flex flex-1">
            {prefix && (
              <InputGroupAddon align="inline-start">
                {prefix}
              </InputGroupAddon>
            )}
            {inputElement}
            {suffix && (
              <InputGroupAddon align="inline-end">
                {suffix}
              </InputGroupAddon>
            )}
          </div>
          {addonAfter && <InputGroupAddon align="inline-end">{addonAfter}</InputGroupAddon>}
        </InputGroup>
      )
    }

    return (
      <InputGroup
        ref={ref}
        className={cn(
          inputNumberVariants({ variant, size }),
          !bordered && "border-transparent",
          disabled && "opacity-50 cursor-not-allowed",
          readOnly && "cursor-default",
          className
        )}
        style={style}
        {...props}
      >
        {prefix && (
          <InputGroupAddon align="inline-start">
            {prefix}
          </InputGroupAddon>
        )}
        {inputElement}
        {suffix && (
          <InputGroupAddon align="inline-end">
            {suffix}
          </InputGroupAddon>
        )}
      </InputGroup>
    )
  }
)

