import * as React from "react"
import { Star } from "lucide-react"
import { cn } from "@/lib/utils"

export interface RateProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * 当前值
   */
  value?: number
  /**
   * 星星总数
   */
  count?: number
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 是否允许清除
   */
  allowClear?: boolean
  /**
   * 变化回调
   */
  onChange?: (value: number) => void
  /**
   * 单元格键值
   */
  cellKey?: string
  /**
   * 是否显示分数
   */
  showScore?: boolean
  /**
   * 大小
   */
  size?: 'sm' | 'md' | 'lg'
}

const Rate = React.forwardRef<HTMLDivElement, RateProps>(
  (
    {
      value = 0,
      count = 5,
      disabled = false,
      allowClear = true,
      onChange,
      cellKey,
      showScore = false,
      size = 'md',
      className,
      ...props
    },
    ref
  ) => {
    const [hoverValue, setHoverValue] = React.useState<number | null>(null)
    const currentValue = hoverValue !== null ? hoverValue : value

    const handleClick = (index: number) => {
      if (disabled) return

      const newValue = index + 1
      if (allowClear && value === newValue) {
        onChange?.(0)
      } else {
        onChange?.(newValue)
      }
    }

    const handleMouseEnter = (index: number) => {
      if (disabled) return
      setHoverValue(index + 1)
    }

    const handleMouseLeave = () => {
      setHoverValue(null)
    }

    const getStarColor = (index: number) => {
      if (index < currentValue) {
        if (currentValue < count * 0.4) return 'text-red-500'
        if (currentValue < count * 0.6) return 'text-yellow-500'
        return 'text-green-500'
      }
      return 'text-gray-300'
    }

    const sizeClasses = {
      sm: 'w-4 h-4',
      md: 'w-6 h-6',
      lg: 'w-8 h-8'
    }

    return (
      <div
        ref={ref}
        className={cn(
          "rate-component flex items-center gap-1",
          disabled && "opacity-50 cursor-not-allowed",
          className
        )}
        {...props}
      >
        {showScore && value > 0 && (
          <span className="mr-2 text-sm font-medium">
            {value}/{count}
          </span>
        )}
        {Array.from({ length: count }).map((_, index) => (
          <Star
            key={index}
            className={cn(
              sizeClasses[size],
              "transition-all duration-200",
              getStarColor(index),
              !disabled && "cursor-pointer hover:scale-110"
            )}
            fill={index < currentValue ? "currentColor" : "none"}
            onClick={() => handleClick(index)}
            onMouseEnter={() => handleMouseEnter(index)}
            onMouseLeave={handleMouseLeave}
          />
        ))}
      </div>
    )
  }
)

Rate.displayName = "Rate"

export default Rate

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { X } from "lucide-react"

const selectVariants = cva(
  "relative border transition-colors",
  {
    variants: {
      variant: {
        default: "border-border bg-background",
        outline: "border-2 border-primary",
        filled: "border-primary/20 bg-primary/5",
        ghost: "border-transparent hover:bg-accent/50",
      },
      size: {
        sm: "h-8 text-sm",
        md: "h-10 text-base",
        lg: "h-12 text-lg",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "md",
    },
  }
)

export interface FormSelectProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange" | "onBlur" | "onFocus">,
  VariantProps<typeof selectVariants> {
  /**
   * 当前值
   */
  value?: string
  /**
   * 默认值
   */
  defaultValue?: string
  /**
   * 占位符
   */
  placeholder?: string
  /**
   * 选项列表
   */
  options?: Array<{ value: string; label: string; disabled?: boolean }>
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 是否只读
   */
  readOnly?: boolean
  /**
   * 是否显示边框
   */
  bordered?: boolean
  /**
   * 是否显示清除按钮
   */
  allowClear?: boolean
  /**
   * 是否支持搜索
   */
  showSearch?: boolean
  /**
   * 是否显示下拉箭头
   */
  showArrow?: boolean
  /**
   * 是否自动获取焦点
   */
  autoFocus?: boolean
  /**
   * 默认是否展开
   */
  defaultOpen?: boolean
  /**
   * 下拉菜单和选择器同宽
   */
  dropdownMatchSelectWidth?: boolean
  /**
   * 值改变时的回调
   */
  onChange?: (value: string) => void
  /**
   * 失去焦点时的回调
   */
  onBlur?: () => void
  /**
   * 获得焦点时的回调
   */
  onFocus?: () => void
}

const FormSelect = React.forwardRef<HTMLDivElement, FormSelectProps>(
  ({
    className,
    variant,
    size,
    value,
    defaultValue,
    placeholder = "请选择",
    options = [],
    disabled = false,
    readOnly = false,
    bordered = true,
    allowClear = false,
    showSearch = false,
    showArrow = true,
    autoFocus = false,
    defaultOpen = false,
    dropdownMatchSelectWidth = true,
    onChange,
    onBlur,
    onFocus,
    ...props
  }, ref) => {
    const [internalValue, setInternalValue] = React.useState(defaultValue || "")
    const [isOpen, setIsOpen] = React.useState(defaultOpen)
    const [searchValue, setSearchValue] = React.useState("")
    const [isHovered, setIsHovered] = React.useState(false)
    const selectRef = React.useRef<HTMLButtonElement>(null)

    const handleValueChange = (newValue: string) => {
      if (readOnly) return
      setInternalValue(newValue)
      setSearchValue("") // 选择后清空搜索
      onChange?.(newValue)
    }

    const handleClear = (e: React.MouseEvent) => {
      e.stopPropagation()
      e.preventDefault()
      if (readOnly) return
      setInternalValue("")
      setSearchValue("")
      setIsOpen(false) // 确保清除后Select关闭
      onChange?.("")
    }

    const handleSearchChange = (value: string) => {
      setSearchValue(value)
    }

    const currentValue = value !== undefined ? value : internalValue
    const showClear = allowClear && currentValue && !disabled && !readOnly

    // 过滤选项
    const filteredOptions = React.useMemo(() => {
      if (!showSearch || !searchValue.trim()) {
        return options
      }
      return options.filter(option =>
        option.label.toLowerCase().includes(searchValue.toLowerCase()) ||
        option.value.toLowerCase().includes(searchValue.toLowerCase())
      )
    }, [options, searchValue, showSearch])

    return (
      <div
        ref={ref}
        className={cn(
          selectVariants({ variant, size }),
          !bordered && "border-transparent",
          disabled && "opacity-50 cursor-not-allowed",
          readOnly && "cursor-default",
          className
        )}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
        {...props}
      >
        <Select
          value={currentValue}
          onValueChange={handleValueChange}
          disabled={disabled || readOnly}
          open={isOpen}
          onOpenChange={(open) => {
            setIsOpen(open)
            if (open) {
              onFocus?.()
            } else {
              onBlur?.()
            }
          }}
        >
          <div className="relative">
            <SelectTrigger
              ref={selectRef}
              className={cn(
                "w-full border-0 bg-transparent h-full px-3"
              )}
              aria-invalid={props['aria-invalid']}
            >
              <SelectValue placeholder={placeholder} />
            </SelectTrigger>
            {showClear && (
              <button
                type="button"
                onClick={handleClear}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors bg-gray-200 rounded-full"
              >
                <X className="h-4 w-4" />
              </button>
            )}
          </div>
          <SelectContent
            className={cn(
              dropdownMatchSelectWidth && "w-[var(--radix-select-trigger-width)]"
            )}
          >
            {showSearch && (
              <div className="px-3 py-2 border-b">
                <input
                  type="text"
                  placeholder="搜索选项..."
                  value={searchValue}
                  onChange={(e) => handleSearchChange(e.target.value)}
                  className="w-full px-2 py-1 text-sm border rounded focus:outline-none focus:ring-1 focus:ring-blue-500"
                  onClick={(e) => e.stopPropagation()}
                />
              </div>
            )}
            {filteredOptions.length > 0 ? (
              filteredOptions.map((option) => (
                <SelectItem
                  key={option.value}
                  value={option.value}
                  disabled={option.disabled}
                >
                  {option.label}
                </SelectItem>
              ))
            ) : (
              showSearch && searchValue && (
                <div className="px-3 py-2 text-sm text-muted-foreground text-center">
                  没有找到匹配的选项
                </div>
              )
            )}
          </SelectContent>
        </Select>
      </div>
    )
  }
)

FormSelect.displayName = "FormSelect"

export { FormSelect }

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"
import { Slider } from "@/registry/ui/slider"

const sliderVariants = cva(
  "relative",
  {
    variants: {
      variant: {
        default: "",
        outline: "",
        filled: "",
        ghost: "",
      },
      size: {
        sm: "text-sm",
        md: "text-base",
        lg: "text-lg",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "md",
    },
  }
)

export interface SliderProps
  extends Omit<React.HTMLAttributes<HTMLDivElement>, "onChange" | "defaultValue">,
    VariantProps<typeof sliderVariants> {
  /**
   * 当前值
   */
  value?: number | number[]
  /**
   * 默认值
   */
  defaultValue?: number | number[]
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 是否只读
   */
  readOnly?: boolean
  /**
   * 最小值
   */
  min?: number
  /**
   * 最大值
   */
  max?: number
  /**
   * 步长
   */
  step?: number
  /**
   * 双滑块模式（范围选择）
   */
  range?: boolean
  /**
   * 拖拽到刻度上
   */
  dots?: boolean
  /**
   * 刻度标记
   */
  marks?: Array<{ number: number; label: string }>
  /**
   * 垂直方向
   */
  vertical?: boolean
  /**
   * 反向坐标轴
   */
  reverse?: boolean
  /**
   * 值变化回调
   */
  onChange?: (value: number | number[]) => void
  /**
   * 拖拽结束回调
   */
  onAfterChange?: (value: number | number[]) => void
}

const FormSlider = React.forwardRef<HTMLDivElement, SliderProps>(
  (
    {
      className,
      value: controlledValue,
      defaultValue = 10,
      disabled = false,
      readOnly = false,
      min = 0,
      max = 100,
      step = 1,
      range = false,
      dots = false,
      marks,
      vertical = false,
      reverse = false,
      onChange,
      onAfterChange,
      variant,
      size,
      style,
      ...props
    },
    ref
  ) => {
    // 确定默认值 - 兼容dashboard的逻辑
    const getDefaultValue = React.useCallback(() => {
      if (range) {
        // 范围模式：确保是数组，类似dashboard的逻辑
        if (Array.isArray(defaultValue)) {
          return defaultValue.length >= 2 ? defaultValue : [min, max]
        }
        return [min, max]
      } else {
        // 单值模式：确保是单个数字
        if (Array.isArray(defaultValue)) {
          return [defaultValue[0] ?? min]
        }
        return [typeof defaultValue === 'number' ? defaultValue : min]
      }
    }, [defaultValue, range, min, max])

    const [internalValue, setInternalValue] = React.useState<number[]>(
      getDefaultValue()
    )

    const isControlled = controlledValue !== undefined
    const currentValue = isControlled
      ? (Array.isArray(controlledValue) ? controlledValue : [controlledValue])
      : internalValue

    // 处理值变化
    const handleValueChange = React.useCallback(
      (newValue: number[]) => {
        if (readOnly) return

        if (!isControlled) {
          setInternalValue(newValue)
        }

        // 根据range模式返回不同格式的值，兼容dashboard
        onChange?.(range ? newValue : newValue[0])
      },
      [isControlled, range, readOnly, onChange]
    )

    // 处理拖拽结束
    const handleValueCommit = React.useCallback(
      (newValue: number[]) => {
        // 根据range模式返回不同格式的值
        onAfterChange?.(range ? newValue : newValue[0])
      },
      [range, onAfterChange]
    )

    // 处理marks - 计算每个刻度的位置百分比
    const processedMarks = React.useMemo(() => {
      if (!marks || marks.length === 0) return undefined

      const range = max - min
      return marks.map(mark => {
        const position = ((mark.number - min) / range) * 100
        return {
          value: mark.number,
          label: mark.label,
          position: Math.max(0, Math.min(100, position)) // 限制在 0-100 之间
        }
      }).sort((a, b) => a.value - b.value)
    }, [marks, min, max])

    return (
      <div
        ref={ref}
        className={cn(
          sliderVariants({ variant, size }),
          vertical ? "flex flex-row items-center justify-center h-40" : "",
          className
        )}
        style={style}
        {...props}
      >
        <Slider
          {...(isControlled ? { value: currentValue } : { defaultValue: getDefaultValue() })}
          onValueChange={handleValueChange}
          onValueCommit={handleValueCommit}
          disabled={disabled || readOnly}
          min={min}
          max={max}
          step={step}
          orientation={vertical ? "vertical" : "horizontal"}
          inverted={reverse}
          key={'slider-' + (range ? 'range' : 'single')}
          className={cn(
            vertical ? "justify-center h-full w-2" : ""
          )}
        />
        {processedMarks && (
          <div className={cn(
            "relative text-xs text-muted-foreground",
            vertical ? "ml-4 h-full" : "mt-2 w-full"
          )}>
            {processedMarks.map((mark) => (
              <div
                key={mark.value}
                className="absolute"
                style={{
                  [vertical ? "bottom" : "left"]: `${mark.position}%`,
                  [vertical ? "left" : "top"]: vertical ? "0" : "0",
                  transform: vertical ? "translateY(50%)" : "translateX(-50%)"
                }}
              >
                {mark.label}
              </div>
            ))}
          </div>
        )}
      </div>
    )
  }
)

FormSlider.displayName = "FormSlider"

export { FormSlider }

