import { TableFieldLink } from '@/registry/blocks/table-field/table-field-link/table-field-link'
import { TableFieldEditableTable } from '@/registry/blocks/table-field/table-field-editable-table/table-field-editable-table'

export interface FormWidgetProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * 字段配置（schema）
   */
  config?: Record<string, any>
  /**
   * 字段值
   */
  value?: any
  /**
   * 输入对象
   */
  input?: {
    value?: any
    onChange?: (value: any) => void
  }
  /**
   * 默认值
   */
  defaultValue?: any
  /**
   * 单元格键值
   */
  cellKey?: string
  /**
   * 字段配置项
   */
  fieldSchema?: string
  /**
   * 是否禁用
   */
  disabled?: boolean
  /**
   * 字段标签
   */
  label?: string
  /**
   * 占位符
   */
  placeholder?: string
  /**
   * 是否必填
   */
  required?: boolean
  /**
   * 描述文本
   */
  description?: string
  /**
   * 错误提示
   */
  error?: string
  /**
   * 大小
   */
  size?: 'small' | 'middle' | 'large'
  /**
   * 元数据
   */
  meta?: any
  /**
   * 记录数据
   */
  record?: any
}

/**
 * 根据字段 schema 选择对应的组件
 */
const FieldComponentSelector: React.FC<{
  schema: Record<string, any>
  input: {
    value?: any
    onChange?: (value: any) => void
    onBlur?: (e: any) => void
  }
  field?: {
    schema?: Record<string, any>
    filter?: any
    meta?: any
  }
  meta?: any
  record?: any
  cellKey?: string
}> = ({ schema, input, field, meta, record, cellKey }) => {
  const config = schema || {}

  // 关联字段（新版）- 使用 recordSelectType
  if ((config.relateTo || config.relate) && config.recordSelectType) {
    const tableID = config.relate?.id || config.relateTo
    return <TableFieldRelatePlus relateSchema={config} tableID={tableID} input={input} field={field ? { schema: config, ...field } : { schema: config }} meta={meta} schema={schema} />
  }

  // 外部工作表关联 - 使用 relate?.id
  const convertedRelateSchema = React.useMemo(() => {
    return ['object', 'array'].includes(config.type) && config.relate?.id
      ? schemaConverter(config, {})
      : null
  }, [config])

  if (convertedRelateSchema) {
    const relateProps = {
      input,
      field: {
        schema: convertedRelateSchema.schema,
        fieldSchema: convertedRelateSchema.fieldSchema,
        displayField: convertedRelateSchema.displayField,
        tableID: convertedRelateSchema.tableID,
        relateShowFields: convertedRelateSchema.relateShowFields,
        key: convertedRelateSchema.key,
        option: {
          form: {
            change: (field: string, value: any) => {
              // TODO: 实现表单字段联动
              console.log('Relate field change:', field, value)
            }
          }
        }
      },
      meta,
      record,
      label: config.title || '请选择',
    }

    // 根据 type 选择对应组件
    if (convertedRelateSchema.type === 'relate_multi_select') {
      return <RelateMultiSelect {...relateProps} />
    }
    if (convertedRelateSchema.type === 'relate_fkselect') {
      return <RelateSelect {...relateProps} />
    }
    if (convertedRelateSchema.type === 'relate_list_fkselect') {
      return <RelateModelSelect {...relateProps} />
    }
  }

  // 内部表关联（internalTable）
  if (config.internalTable && config.relate) {
    return <RelateComponent input={input} field={{ schema: config, ...field, internalTable: true }} meta={meta} record={record} />
  }

  // 附件上传
  if (config.type === 'object' && config.fieldType === 'attachment') {
    return <TableFieldUpload input={input} field={{ schema: config, meta }} type="upload_attachment" />
  }

  if (config.type === 'array' && config.fieldType === 'attachments') {
    return <TableFieldUpload input={input} field={{ schema: config, meta }} type="upload_attachment_group" />
  }

  // 用户/角色关联
  if (['User', 'Role'].includes(config.relateTo || '')) {
    return <TableFieldUserRole input={input} field={{ schema: config, displayField: config.showField || 'name' }} meta={meta} record={record} />
  }

  // 关联字段只读
  if ((config.relateTo || config.relate) && config.disabled) {
    // TODO: 实现关联字段只读组件
    return <div className="text-sm text-muted-foreground">关联字段只读（待实现）</div>
  }

  // 文本输入
  if (config.type === 'string' && config.fieldType === 'input') {
    return <TableFieldText input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 枚举选择器
  if (config.enum1 && config.enum1.length > 0) {
    return <TableFieldSelect input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 数字输入
  if (config.type === 'number' && config.fieldType === 'inputNumber') {
    return <TableFieldNumber input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 日期选择
  if (config.type === 'string' && config.fieldType === 'datePicker') {
    return <TableFieldDate input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 日期范围
  if (config.type === 'string' && config.fieldType === 'dateRange') {
    return <TableFieldDateRange input={input} field={{ schema: config, meta }} meta={meta} record={record} cellKey={cellKey} />
  }

  // 时间选择
  if (config.type === 'string' && config.fieldType === 'timePicker') {
    return <TableFieldTime input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 地图定位
  if (config.type === 'object' && config.fieldType === 'map') {
    return <TableFieldMap input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 布尔值/复选框
  if (config.type === 'boolean' && (config.fieldType === 'checkbox' || config.fieldType === 'boolean')) {
    return <TableFieldCheckbox input={input} field={{ schema: config, meta }} meta={meta} record={record} label={config.title} />
  }

  // 可编辑表格
  if (config.fieldType === 'editableTable') {
    return <TableFieldEditableTable input={input} schema={config} meta={meta} record={record} />
  }

  // 只读表格
  if (config.fieldType === 'showTable') {
    // TODO: 实现只读表格组件
    return <div className="text-sm text-muted-foreground">只读表格（待实现）</div>
  }

  // 编号
  if (config.fieldType === 'serialNumber') {
    return <TableFieldSerialNumber input={input} field={{ schema: config }} />
  }

  // 链接
  if (config.fieldType === 'link') {
    return <TableFieldLink input={input} field={{ schema: config }} meta={meta} record={record} />
  }

  // 区域选择
  if (config.fieldType === 'area') {
    const areaInput = {
      value: input.value,
      onChange: input.onChange || (() => {})
    }
    return <AreaComponent input={areaInput} field={{ schema: config }} meta={meta || {}} areaType={config.areaType || 'pca'} />
  }

  // 报警关联
  if (config.relateTo === 'Warning') {
    // TODO: 实现报警组件
    return <div className="text-sm text-muted-foreground">报警（待实现）</div>
  }

  // 星级评价
  if (config.fieldType === 'rate') {
    return <TableFieldRate input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 富文本编辑器
  if (config.fieldType === 'textEditor') {
    return <TableFieldRichText input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  // 字节数组
  if (config.fieldType === 'bytesArray') {
    return <TableFieldBytesArray input={input} field={{ schema: config, filter: null }} meta={meta} record={record} />
  }

  // 多语言输入
  if (config.fieldType === 'languageInput') {
    // TODO: 实现多语言输入组件
    return <div className="text-sm text-muted-foreground">多语言输入（待实现）</div>
  }

  // 查找引用
  if (config.config === '查找引用') {
    return <TableFieldReference schema={config} field={{ key: config.key }} option={{ schema: { name: schema?.name } }} tableData={record} />
  }

  // 表单信息
  if (config.config === '表单信息') {
    return <TableFieldFormInfo schema={config} outProps={{ inList: false, viewPage: true }} />
  }

  // 默认：根据基础类型显示
  if (config.type === 'string') {
    return <TableFieldText input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  if (config.type === 'number') {
    return <TableFieldNumber input={input} field={{ schema: config, meta }} meta={meta} record={record} />
  }

  if (config.type === 'boolean') {
    return <TableFieldCheckbox input={input} field={{ schema: config, meta }} meta={meta} record={record} label={config.title} />
  }

  // 未知类型
  return (
    <div className="text-sm text-muted-foreground">
      未知字段类型: {config.type} {config.fieldType}
    </div>
  )
}

/**
 * FormWidget - 表字段映射组件
 * 根据字段配置动态渲染对应的表单组件
 */
const FormWidget = React.forwardRef<HTMLDivElement, FormWidgetProps>(
  (
    {
      config = {},
      input,
      defaultValue,
      cellKey,
      disabled = false,
      label,
      placeholder,
      required = false,
      description,
      error,
      size = 'middle',
      meta,
      record,
      className,
      fieldSchema,
      ...props
    },
    ref
  ) => {
    let schema
    try {
      schema = fieldSchema ? JSON.parse(fieldSchema) : {}
    } catch (e) {
      console.error('解析 fieldSchema 出错', e)
    }

    const [insideVal, setInsideVal] = React.useState<any>(defaultValue)

    // 处理输入值
    const inputValue = input?.value || insideVal

    // 处理值变化
    const handleChange = React.useCallback((newValue: any) => {
      if (input?.onChange) {
        input.onChange(newValue)
      } else {
        setInsideVal(newValue)
      }
    }, [input])

    const inputProps = React.useMemo(() => ({
      value: inputValue,
      onChange: handleChange
    }), [inputValue, handleChange])

    // 空配置时的占位显示
    if (isEmpty(schema)) {
      return (
        <div
          ref={ref}
          className={cn(
            "form-widget flex items-center justify-center",
            "min-h-[130px] w-full text-sm text-muted-foreground",
            className
          )}
          {...props}
        >
          能够配置表定义中定义的所有字段
        </div>
      )
    }

    return (
      <div ref={ref} className={cn("form-widget space-y-2", className)} {...props}>
        {label && (
          <label className={cn(
            "text-sm font-medium leading-none",
            "peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
          )}>
            {label}
            {required && <span className="text-red-500 ml-1">*</span>}
          </label>
        )}

        <FieldComponentSelector
          schema={schema}
          input={inputProps}
          field={{ schema, meta }}
          meta={meta}
          record={record}
          cellKey={cellKey}
        />

        {description && (
          <p className="text-sm text-muted-foreground">{description}</p>
        )}

        {error && (
          <p className="text-sm text-red-500">{error}</p>
        )}
      </div>
    )
  }
)

FormWidget.displayName = "FormWidget"

export { FieldComponentSelector }

export default FormWidget

import {
  FieldGroup
} from "@/components/ui/field"
import { FormProvider, useForm, useFormSchema, type UseFormPropsExtended, type UseFormSchemaProps } from '@airiot/client'
import type { ReactNode } from 'react'

import FormField from "@/registry/blocks/form/form-field/form-field"

type SchemaFormProps = UseFormPropsExtended & UseFormSchemaProps & {
  formId: string
  onSubmit: (data: any) => void
  children?: ReactNode | ((props: any) => ReactNode)
  classNames?: Record<'form' | 'group' | 'field' | 'label' | 'input' | 'description' | 'error', string>
}

const SchemaForm = ({ schema, formSchema, onSubmit, formId, children, classNames, ...props }: SchemaFormProps) => {
  const { fields, resolver } = useFormSchema({ schema, formSchema })
  const methods = useForm({
    resolver: resolver, ...props
  } as any)

  return (
    <FormProvider {...methods} classNames={classNames}>
      <form id={formId} onSubmit={methods.handleSubmit(onSubmit)} className={classNames?.form}>
        <FieldGroup className={classNames?.group}>
          {fields.map(field => (
            <FormField {...field} key={field.key} />
          ))}
        </FieldGroup>
        {children ? ( typeof children === 'function' ? children({
          ...methods
        }) : children ) : null}
      </form>
    </FormProvider>
  )
}

export default SchemaForm

import * as React from "react"
import { cn } from "@/lib/utils"
import TileLayer from 'ol/layer/Tile'
import OSM from 'ol/source/OSM'
import XYZ from 'ol/source/XYZ'
import type Map from 'ol/Map'
import { useMap } from '../map-container/map-container'

export interface CodeParam {
  name: string
  value: string | number | boolean | Record<string, unknown>
}

export interface CodeEditorViewsProps {
  /**
   * 代码脚本
   */
  codeScript?: string
  /**
   * 参数列表
   */
  params?: CodeParam[]
  /**
   * 是否显示
   */
  display?: boolean
  /**
   * CSS 类名
   */
  className?: string
  /**
   * 单元格唯一标识
   */
  cellKey?: string
  /**
   * 地图实例（由父组件传入）
   */
  map?: Map | null
}

// 提供给脚本使用的 OpenLayers 模块
const olModules = {
  layer: {
    Tile: TileLayer,
  },
  source: {
    OSM,
    XYZ,
  },
}

const CodeEditorViews = React.forwardRef<HTMLDivElement, CodeEditorViewsProps>(
  (
    {
      className,
      codeScript,
      params = [],
      display = true,
      cellKey,
      map: mapProp,
      ...props
    },
    ref
  ) => {
    const contextMap = useMap()
    const map = mapProp || contextMap
    const layerRef = React.useRef<TileLayer<OSM | XYZ> | null>(null)

    // 统一计算图层是否应该显示
    const shouldShow = React.useMemo(() => {
      return display == null || display
    }, [display])

    // 执行代码脚本
    React.useEffect(() => {
      if (!map || !codeScript) return

      try {
        // 构建参数对象
        const paramsObj: Record<string, unknown> = {}
        params?.forEach((item) => {
          const v = item.value && typeof item.value === 'object' && 'vval' in item.value 
            ? (item.value as Record<string, unknown>).vval 
            : item.value
          paramsObj[item.name] = v
        })

        // 执行脚本
        // eslint-disable-next-line no-eval
        const scriptFn = eval(codeScript)
        if (typeof scriptFn === 'function') {
          layerRef.current = scriptFn({ ...olModules, map }, paramsObj)
          if (layerRef.current) {
            layerRef.current.setVisible(shouldShow)
          }
        }
      } catch (error) {
        console.error('CodeEditorViews script error:', error)
      }

      return () => {
        if (layerRef.current && map) {
          try {
            map.removeLayer(layerRef.current)
          } catch (e) {
            // ignore
          }
          layerRef.current = null
        }
      }
    }, [map, codeScript, JSON.stringify(params)])

    // display 变化时，仅更新图层可见性
    React.useEffect(() => {
      if (!map || !layerRef.current) return
      layerRef.current.setVisible(shouldShow)
    }, [map, shouldShow])

    return (
      <div
        ref={ref}
        className={cn("code-editor-views", className)}
        style={{ display: 'none' }}
        data-cell-key={cellKey}
        {...props}
      />
    )
  }
)

CodeEditorViews.displayName = "CodeEditorViews"

export { CodeEditorViews }

import * as React from "react"
import { cn } from "@/lib/utils"
import { Vector as VectorLayer } from 'ol/layer'
import { Vector as VectorSource } from 'ol/source'
import Feature from 'ol/Feature'
import * as geom from 'ol/geom'
import * as style from 'ol/style'
import { fromLonLat } from 'ol/proj'
import type Map from 'ol/Map'
import { useMap } from '../map-container/map-container'

export interface LocationData {
  type: 'Point' | 'LineString' | 'Polygon' | 'Circle'
  coordinates: number[] | number[][] | number[][][] | { center: number[]; radius: number }
}

export interface DrawLineItem {
  location?: {
    data?: LocationData[]
    style?: {
      point?: PointStyle
      line?: LineStyle
    }
  } & LocationData
  style?: {
    point?: PointStyle
    line?: LineStyle
  }
  [key: string]: unknown
}

export interface PointStyle {
  src?: string
  scale?: number
  color?: string
}

export interface LineStyle {
  color?: string
  width?: number
  fillColor?: string
  snumber?: boolean
}

export interface FeatureStyle {
  point?: PointStyle
  line?: LineStyle
}

export interface CustomViewsProps {
  /**
   * 绑定的外部数据
   */
  drawLine?: DrawLineItem[]
  /**
   * 要素样式配置
   */
  featureStyle?: FeatureStyle
  /**
   * 是否显示
   */
  display?: boolean
  /**
   * CSS 类名
   */
  className?: string
  /**
   * 单元格唯一标识
   */
  cellKey?: string
  /**
   * 地图实例（由父组件传入）
   */
  map?: Map | null
}

// 默认点图标
const DEFAULT_POINT_ICON = 'data:image/svg+xml;base64,'

const CustomViews = React.forwardRef<HTMLDivElement, CustomViewsProps>(
  (
    {
      className,
      drawLine = "",
      featureStyle = {},
      display = true,
      cellKey,
      map: mapProp,
      ...props
    },
    ref
  ) => {
    const contextMap = useMap()
    const map = mapProp || contextMap
    const layerRef = React.useRef<VectorLayer<VectorSource> | null>(null)

    // 统一计算图层是否应该显示
    const shouldShow = React.useMemo(() => {
      return display == null || display
    }, [display])

    // 坐标转换函数
    const transformTo3857 = React.useCallback((coord: number[]) => {
      return fromLonLat(coord)
    }, [])

    // 根据 drawLine 外部数据去绘制图层
    React.useEffect(() => {
      if (!map) return

      // 先移除旧图层
      if (layerRef.current) {
        map.removeLayer(layerRef.current)
        layerRef.current = null
      }


      if (!drawLine || !Array.isArray(drawLine) || !drawLine.length) return

      const features: Feature[] = []

      const buildFeatureFromGeom = (g: LocationData, index: number, item: DrawLineItem) => {
        if (!g || !g.type) return null
        let featureGeom: geom.Geometry | null = null

        if (g.type === 'Point') {
          const coord = g.coordinates as number[]
          if (!coord || coord.length < 2) return null
          featureGeom = new geom.Point(transformTo3857(coord))
        } else if (g.type === 'LineString') {
          const coords = (g.coordinates || []) as number[][]
          if (!coords.length) return null
          featureGeom = new geom.LineString(coords.map(c => transformTo3857(c)))
        } else if (g.type === 'Polygon') {
          const rings = (g.coordinates || []) as number[][][]
          if (!rings.length) return null
          const transformed = rings.map(r => r.map(c => transformTo3857(c)))
          featureGeom = new geom.Polygon(transformed)
        } else if (g.type === 'Circle') {
          const circleCoords = g.coordinates as { center: number[]; radius: number }
          const center = circleCoords?.center
          const radius = circleCoords?.radius
          if (!center || !radius) return null
          featureGeom = new geom.Circle(transformTo3857(center), radius)
        }

        if (!featureGeom) return null

        const f = new Feature({
          geometry: featureGeom,
          customIndex: index,
          customData: item,
          cellKey,
        })
        return f
      }

      drawLine.forEach((item, index) => {
        const loc = item?.location
        if (!loc) return

        // 支持 location.data 数组 或 单个 geometry 对象
        if (Array.isArray(loc.data)) {
          loc.data.forEach(g => {
            const f = buildFeatureFromGeom(g, index, item)
            if (f) features.push(f)
          })
        } else if (loc.type) {
          const f = buildFeatureFromGeom(loc as LocationData, index, item)
          if (f) features.push(f)
        }
      })

      if (!features.length) return

      const source = new VectorSource({ features })
      const layer = new VectorLayer({
        source,
        properties: { layerType: 'custom', cellKey },
        zIndex: 100,
      })

      // 样式函数
      layer.setStyle((feature) => {
        const geometry = feature.getGeometry()
        if (!geometry) return undefined

        const geomType = geometry.getType()
        const data = feature.get('customData') || {}
        const dataStyleRoot = data?.location?.style || data.style || {}

        // 根据几何类型获取样式，合并优先级：数据样式 < 图层样式
        let mergedStyle: PointStyle | LineStyle = {}
        if (geomType === 'Point') {
          const dataPointStyle = dataStyleRoot.point || {}
          const layerPointStyle = featureStyle?.point || {}
          mergedStyle = { ...dataPointStyle, ...layerPointStyle }
        } else {
          const dataLineStyle = dataStyleRoot.line || {}
          const layerLineStyle = featureStyle?.line || {}
          mergedStyle = { ...dataLineStyle, ...layerLineStyle }
        }
        if (geomType === 'Point') {
          const pointStyle = mergedStyle as PointStyle
          return new style.Style({
            image: new style.Icon({
              src: pointStyle.src || DEFAULT_POINT_ICON,
              scale: pointStyle.scale || 1,
              anchor: [0.5, 1],
            }),
          })
        }

        // 线、面、圆
        const lineStyle = mergedStyle as LineStyle
        const strokeColor = lineStyle.color || 'rgba(255, 0, 0, 0.8)'
        const strokeWidth = lineStyle.width || 2
        const fillColor = lineStyle.fillColor || 'rgba(255, 0, 0, 0.2)'

        return new style.Style({
          stroke: new style.Stroke({
            color: strokeColor,
            width: strokeWidth,
          }),
          fill: new style.Fill({
            color: fillColor,
          }),
        })
      })

      layer.setVisible(shouldShow)
      map.addLayer(layer)
      layerRef.current = layer

      return () => {
        if (layerRef.current && map) {
          map.removeLayer(layerRef.current)
          layerRef.current = null
        }
      }
    }, [map, JSON.stringify(drawLine), JSON.stringify(featureStyle), cellKey, transformTo3857])

    // display 变化时，仅更新图层可见性
    React.useEffect(() => {
      if (!map || !layerRef.current) return
      layerRef.current.setVisible(shouldShow)
    }, [map, shouldShow])

    return (
      <div
        ref={ref}
        className={cn("custom-views", className)}
        style={{ display: 'none' }}
        data-cell-key={cellKey}
        {...props}
      />
    )
  }
)

