import * as React from "react"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import {
  Drawer,
  DrawerContent,
  DrawerClose,
  DrawerPortal
} from "@/registry/ui/drawer"
import { toast } from "sonner"
import { QrCode } from "lucide-react"

export interface MobileScanQRProps extends Omit<React.HTMLAttributes<HTMLButtonElement>, "onChange"> {
  /**
   * 按钮文字
   */
  text?: string
  /**
   * 二维码扫描成功回调
   */
  onSuccess?: (data: string) => void
  /**
   * 值变化回调
   */
  onChange?: (value: string) => void
  /**
   * 扫描二维码 url 跳转事件
   */
  onRoute?: (url: string) => void
}

const MobileScanQR = React.forwardRef<HTMLButtonElement, MobileScanQRProps>(
  (
    {
      className,
      text = "扫描二维码",
      onSuccess,
      onChange,
      onRoute,
      ...props
    },
    ref
  ) => {
    const [visible, setVisible] = React.useState(false)
    const [isScanning, setIsScanning] = React.useState(false)
    const canvasRef = React.useRef<HTMLCanvasElement>(null)
    const videoRef = React.useRef<HTMLVideoElement>(null)
    const animationRef = React.useRef<number>()

    // 获取摄像头流
    const getUserMedia = React.useCallback((constraints: MediaStreamConstraints, success: (stream: MediaStream) => void, error: (err: Error) => void) => {
      const nav = window.navigator as any
      if (nav && nav.mediaDevices && nav.mediaDevices.getUserMedia) {
        // 最新标准 API
        nav.mediaDevices.getUserMedia(constraints).then(success).catch(error)
      } else if (nav.webkitGetUserMedia) {
        // webkit 内核浏览器
        nav.webkitGetUserMedia(constraints).then(success).catch(error)
      } else if (nav.mozGetUserMedia) {
        // Firefox 浏览器
        nav.mozGetUserMedia(constraints).then(success).catch(error)
      } else if (nav.getUserMedia) {
        // 旧版 API
        nav.getUserMedia(constraints).then(success).catch(error)
      } else {
        throw new Error('你的浏览器不支持访问用户媒体设备')
      }
    }, [])

    // 扫描二维码
    const scanQRCode = React.useCallback(async () => {
      const canvas = canvasRef.current
      const video = videoRef.current
      if (!canvas || !video) return

      const ctx = canvas.getContext('2d')
      if (!ctx) return

      if (video.readyState !== video.HAVE_ENOUGH_DATA) return

      canvas.width = canvas.clientWidth
      canvas.height = canvas.clientHeight

      if (canvas.height === 0 && canvas.width === 0) return

      ctx.drawImage(video, 0, 0, canvas.width, canvas.height)
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height)

      // 动态导入 jsQR
      const { default: jsQR } = await import('jsqr')

      const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: "dontInvert" })

      if (code && code.data) {
        const qrData = code.data.trim()
        onChange?.(qrData)
        onSuccess?.(qrData)

        // 判断是否为 URL
        const urlRegex = /^(https?:\/\/|ftp:\/\/|www\.)[^\s/$.?#].[^\s]*$/i
        if (urlRegex.test(qrData)) {
          window.location.href = qrData
        } else {
          onRoute?.(qrData)
        }

        stopScanning()
      }
    }, [onChange, onSuccess, onRoute])

    // 停止扫描
    const stopScanning = React.useCallback(() => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current)
        animationRef.current = undefined
      }
      const video = videoRef.current
      if (video && video.srcObject) {
        const stream = video.srcObject as MediaStream
        stream.getTracks().forEach(track => track.stop())
        video.srcObject = null
      }
      setIsScanning(false)
    }, [])

    // 开始扫描
    const startScanning = React.useCallback(() => {
      const video = videoRef.current
      if (!video) return

      getUserMedia(
        { video: { facingMode: 'environment' } },
        (stream) => {
          video.srcObject = stream
          video.setAttribute("playsinline", "true")
          video.play()
          setIsScanning(true)

          const tick = () => {
            scanQRCode().catch(console.error)
            animationRef.current = requestAnimationFrame(tick)
          }
          tick()
        },
        () => {
          toast.error('访问用户媒体设备失败')
          stopScanning()
        }
      )
    }, [getUserMedia, scanQRCode, stopScanning])

    // 关闭扫描器
    const handleClose = React.useCallback(() => {
      setVisible(false)
      stopScanning()
    }, [stopScanning])

    // 弹窗打开时启动扫描，关闭时停止
    React.useEffect(() => {
      if (visible) {
        setTimeout(() => {
          startScanning()
        }, 100)
      } else {
        stopScanning()
      }
    }, [visible, startScanning, stopScanning])

    // 清理动画帧
    React.useEffect(() => {
      return () => {
        stopScanning()
      }
    }, [stopScanning])

    return (
      <>
        <Button
          ref={ref}
          className={cn("w-full", className)}
          onClick={() => setVisible(true)}
          {...props}
        >
          <QrCode className="h-4 w-4 mr-2" />
          {text}
        </Button>

        <Drawer open={visible} onOpenChange={setVisible} direction="bottom">
          <DrawerPortal>
            <DrawerContent className="h-full">
              <div className="relative flex flex-col h-full bg-black">
                {/* 扫描区域 */}
                <div className="flex-1 relative overflow-hidden">
                  <video
                    ref={videoRef}
                    className="absolute inset-0 w-full h-full object-cover"
                    playsInline
                    muted
                  />
                  <canvas
                    ref={canvasRef}
                    className="qr-canvas absolute inset-0 w-full h-full"
                  />

                  {/* 扫描框 */}
                  <div className="absolute inset-0 flex items-center justify-center">
                    <div className="relative w-64 h-64 border-2 border-white/80 rounded-lg">
                      {/* 扫描线动画 */}
                      {isScanning && (
                        <div className="absolute top-0 left-0 right-0 h-0.5 bg-green-500 animate-[scan_2s_linear_infinite]">
                          <style>{`
                            @keyframes scan {
                              0%, 100% { top: 0; }
                              50% { top: 100%; }
                            }
                          `}</style>
                        </div>
                      )}
                      {/* 四角装饰 */}
                      <div className="absolute top-0 left-0 w-6 h-6 border-t-4 border-l-4 border-green-500 -mt-0.5 -ml-0.5 rounded-tl-lg" />
                      <div className="absolute top-0 right-0 w-6 h-6 border-t-4 border-r-4 border-green-500 -mt-0.5 -mr-0.5 rounded-tr-lg" />
                      <div className="absolute bottom-0 left-0 w-6 h-6 border-b-4 border-l-4 border-green-500 -mb-0.5 -ml-0.5 rounded-bl-lg" />
                      <div className="absolute bottom-0 right-0 w-6 h-6 border-b-4 border-r-4 border-green-500 -mb-0.5 -mr-0.5 rounded-br-lg" />
                    </div>
                  </div>
                </div>

                {/* 底部操作区 */}
                <div className="h-16 bg-white flex items-center justify-between px-4">
                  <span className="text-sm text-slate-600">
                    {isScanning ? '正在扫描...' : '请将二维码放入框内'}
                  </span>
                  <DrawerClose asChild>
                    <Button variant="outline" size="sm" onClick={handleClose}>
                      取消
                    </Button>
                  </DrawerClose>
                </div>

                <DrawerClose />
              </div>
            </DrawerContent>
          </DrawerPortal>
        </Drawer>
      </>
    )
  }
)
MobileScanQR.displayName = "MobileScanQR"

export { MobileScanQR }

import * as React from "react"
import { WebControl } from "./web-control.esm.min.js"

// 初始化参数接口
export interface InitConfig {
  appkey?: string
  ip?: string
  port?: number
  secret?: string
  enableHTTPS?: number
  language?: string
  layout?: string
  playMode?: number
  reconnectDuration?: number
  reconnectTimes?: number
  showSmart?: number
  showToolbar?: number
  toolBarButtonIDs?: string
  snapDir?: string
  videoDir?: string
}

// 节点接口
export interface Node {
  id: string
  [key: string]: any
}

// 预览配置
export interface PlayConfig {
  streamMode?: string
}

// 回放配置
export interface PlayBackConfig {
  startTimeStamp?: string
  endTimeStamp?: string
  playTimeStamp?: string
  recordLocation?: string
}

// 组件属性
export interface IscVideoProps {
  /** 编辑模式 */
  editMode?: boolean
  /** 单元格键 */
  cellKey?: string
  /** 节点列表 */
  nodes?: Node[]
  /** 初始化配置 */
  initConfig?: InitConfig
  /** 预览配置 */
  playConfig?: PlayConfig
  /** 回放配置 */
  playBackConfig?: PlayBackConfig
}

// 获取初始化参数
const getInitArgument = (initConfig?: InitConfig): any => {
  const defaultInit = {
    appkey: "",
    ip: "",
    port: 443,
    secret: "",
    enableHTTPS: 1,
    language: "zh_CN",
    layout: "2x2",
    playMode: 0,
    reconnectDuration: 5,
    reconnectTimes: 5,
    showSmart: 0,
    showToolbar: 1,
    toolBarButtonIDs: "2048,2049,2050,2304,2306,2305,2307,2308,2309,4096,4608,4097,4099,4098,4609,4100",
    snapDir: "D:/snap",
    videoDir: "D:/video",
  }
  return { ...defaultInit, ...initConfig }
}

// 更新播放/回放
const update = async ({
  oWebControl,
  nodes = [],
  initConfig,
  playConfig,
  playBackConfig,
}: {
  oWebControl: any
  nodes: Node[]
  initConfig?: InitConfig
  playConfig?: PlayConfig
  playBackConfig?: PlayBackConfig
}) => {
  const initArgument = getInitArgument(initConfig)
  if (initArgument?.playMode === 0) {
    // 停止所有预览
    await oWebControl.JS_RequestInterface({
      argument: {},
      funcName: "stopAllPreview",
    })
    // 批量播放
    await oWebControl.JS_RequestInterface({
      argument: {
        list: nodes.map((node, index) => ({
          authUuid: "",
          cameraIndexCode: node?.id,
          ezvizDirect: 0,
          gpuMode: 0,
          streamMode: parseInt(playConfig?.streamMode || "0"),
          transMode: 1,
          wndId: index + 1,
        })),
      },
      funcName: "startMultiPreviewByCameraIndexCode",
    })
    console.log("批量播放")
  } else if (initArgument?.playMode === 1) {
    // 停止所有回放
    await oWebControl.JS_RequestInterface({
      argument: {},
      funcName: "stopAllPlayback",
    })
    // 批量回放
    await oWebControl.JS_RequestInterface({
      argument: {
        list: nodes.map((node, index) => ({
          authUuid: "",
          cameraIndexCode: node?.id,
          endTimeStamp: Math.floor(new Date(playBackConfig?.endTimeStamp || Date.now()).getTime() / 1000),
          ezvizDirect: 0,
          gpuMode: 0,
          playTimeStamp: Math.floor(new Date(playBackConfig?.playTimeStamp || Date.now()).getTime() / 1000),
          recordLocation: parseInt(playBackConfig?.recordLocation || "0"),
          startTimeStamp: Math.floor(new Date(playBackConfig?.startTimeStamp || Date.now()).getTime() / 1000),
          transMode: 1,
          wndId: index + 1,
        })),
      },
      funcName: "startMultiPlaybackByCameraIndexCode",
    })
    console.log("批量回放")
  }
}

// 启动插件
const start = ({
  nodes = [],
  initConfig,
  playConfig,
  playBackConfig,
  setInit,
  setActiveWin,
  instanceId,
}: {
  nodes: Node[]
  initConfig?: InitConfig
  playConfig?: PlayConfig
  playBackConfig?: PlayBackConfig
  setInit: (init: boolean) => void
  setActiveWin: (winId: number) => void
  instanceId: string
}) => {
  // 检查 WebControl 是否可用（已通过导入）
  const oWebControl = new WebControl({
    szPluginContainer: `iscPlayWnd-${instanceId}`,
    iServicePortStart: 15900,
    iServicePortEnd: 15900,
    szClassId: "23BF3B0A-2C56-4D97-9C03-0CB103AA8F11",
    cbConnectSuccess: async () => {
      console.log("cbConnectSuccess")
      // 启动服务
      await oWebControl.JS_StartService("window", {
        dllPath: "./VideoPluginConnect.dll",
      })
      console.log("启动服务")
      // 创建窗口
      const container = document.querySelector(`#iscPlayWnd-${instanceId}`)
      if (!container) return
      const { clientWidth, clientHeight } = container as HTMLElement
      await oWebControl.JS_CreateWnd(`iscPlayWnd-${instanceId}`, clientWidth, clientHeight)
      console.log("创建窗口")
      // 获取公钥
      await oWebControl.JS_RequestInterface({
        funcName: "getRSAPubKey",
        argument: JSON.stringify({
          keyLength: 1024,
        }),
      })
      console.log("获取公钥")
      // 初始化
      const initArgument = getInitArgument(initConfig)
      await oWebControl.JS_RequestInterface({
        argument: initArgument,
        funcName: "init",
      })
      setInit(true)
      console.log("初始化")
      update({ oWebControl, nodes, initConfig, playConfig, playBackConfig })
      // 设置窗口大小
      oWebControl.JS_Resize(clientWidth, clientHeight)
      // 监听消息
      oWebControl.JS_SetWindowControlCallback({
        cbIntegrationCallBack({ responseMsg }: any) {
          if (responseMsg?.type === 1) {
            setActiveWin(responseMsg?.msg?.wndId)
          } else if (responseMsg?.type === 6) {
            setActiveWin(1)
          }
        },
      })
    },
    cbConnectError: () => {
      console.log("cbConnectError")
    },
    cbConnectClose: (bNormalClose: boolean) => {
      console.log("cbConnectClose", bNormalClose)
    },
  })
  return oWebControl
}

// 停止插件
const stop = async ({
  oWebControl,
  setInit,
}: {
  oWebControl: any
  setInit: (init: boolean) => void
}) => {
  if (oWebControl) {
    try {
      await oWebControl.JS_RequestInterface({
        funcName: "uninit",
      })
      if (oWebControl.JS_HideWnd) {
        oWebControl.JS_HideWnd()
      }
      await oWebControl.JS_DestroyWnd()
      console.log("销毁成功")
      setInit(false)
    } catch (error) {
      console.error("停止插件失败", error)
    }
  }
}

