  columns?: ColumnItemConfig[]
  statsBySingle?: boolean | null
  limit?: number
  skip?: number
  interval?: number
  showInnerField?: boolean
  feildFormat?: FieldFormatConfig[]
  extraSchema?: any
  submit?: string
}

export interface TableDataSourceProps {
  id?: string
  selectType?: 'table' | 'dataset'
  table?: any
  initFilter?: Record<string, any>
  isGroup?: boolean
  showInnerField?: boolean
  statsBySingle?: any
  feildFormat?: Array<any>
  queryFields?: string[]
  interval?: number
  submit?: string
  children?: ReactNode
